<span class="line"><span style="color:#A6E3A1;">            &quot;Line </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">: </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">fn </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">(</span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;"> params) -&gt; </span><span style="color:#9399B2;">{}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">,</span></span>
