<span class="line"><span style="color:#CDD6F4;">            func</span><span style="color:#94E2D5;">.</span><span style="color:#CDD6F4;">return_type</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">as_deref</span><span style="color:#9399B2;">()</span><span style="color:#94E2D5;">.</span><span style="color:#89B4FA;font-style:italic;">unwrap_or</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;()&quot;</span><span style="color:#9399B2;">)</span></span>
